(function(w){"use strict";const ID="bmi";function compute(x){const h=Number(x.height),weight=Number(x.weight);if(!Number.isFinite(h)||h<=0||!Number.isFinite(weight)||weight<=0)return{error:"키와 몸무게를 올바르게 입력해 주세요."};const bmi=weight/Math.pow(h/100,2);let category=bmi<18.5?"저체중":bmi<23?"정상":bmi<25?"과체중":bmi<30?"비만":"고도비만";return{bmi,category}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>키 (cm)</label><input class="hm-calc-input" inputmode="decimal" placeholder="예: 170"></div><div class="hm-calc-field"><label>몸무게 (kg)</label><input class="hm-calc-input" inputmode="decimal" placeholder="예: 65"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">BMI 계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div><p class="hm-calc-note">BMI는 참고용 지표이며 개인의 건강 상태를 진단하지 않습니다.</p></div>`;const [h,wt]=root.querySelectorAll("input"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({height:api.parseNumber(h.value),weight:api.parseNumber(wt.value)});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("BMI",api.formatNumber(r.bmi,1),`분류: <strong>${r.category}</strong>`));});}w.HM_CALC.register(ID,{compute,render});})(window);
